//Script para insertar el listado de acciones disponibles para operar
//Aqui las acciones tienen el dato del precio y la variacion
// Primero cargar las variables de entorno

import path from 'path'
import { fileURLToPath } from 'url'
import dotenv from 'dotenv'
import Accion from './accion.js'
import mongoose from 'mongoose'

// Configuración de __dirname en ES Modules (reemplazo para CommonJS)
const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)

// Subimos un nivel para llegar a la raíz del proyecto
const envPath = path.join(__dirname, '..', '.env')

// Cargar variables de entorno
dotenv.config({ path: envPath })

// Verificar que la variable de entorno existe
if (!process.env.MONGO_URI) {
  console.error('Error: La variable de entorno MONGO_URI no está definida')
  process.exit(1)
}

