console.log('MONGO_URI:', process.env.MONGO_URI)

// Conectar a MongoDB e insertar las acciones
mongoose
  .connect(process.env.MONGO_URI, {})
  .then(async () => {
    console.log('Conectado a MongoDB')
    try {
      const resultado = await Accion.insertMany(accionesParaInsertar)
      console.log('Acciones insertadas exitosamente:', resultado)
    } catch (error) {
      console.error('Error al insertar las acciones:', error)
    } finally {
      await mongoose.connection.close()
      console.log('Conexión cerrada')
    }
  })
  .catch((error) => {
    console.error('Error al conectar a MongoDB:', error)
    process.exit(1)
  })
